B.a5q=new A.dB("3. C\xe1ch Ch\xfang T\xf4i S\u1eed D\u1ee5ng Th\xf4ng Tin","Th\xf4ng tin \u0111\u01b0\u1ee3c thu th\u1eadp s\u1ebd \u0111\u01b0\u1ee3c s\u1eed d\u1ee5ng \u0111\u1ec3:\n\n\u2022 X\u1eed l\xfd \u0111\u01a1n h\xe0ng v\xe0 cung c\u1ea5p d\u1ecbch v\u1ee5\n\u2022 Li\xean l\u1ea1c v\u1edbi kh\xe1ch h\xe0ng v\u1ec1 \u0111\u01a1n h\xe0ng v\xe0 d\u1ecbch v\u1ee5\n\u2022 C\u1ea3i thi\u1ec7n s\u1ea3n ph\u1ea9m v\xe0 d\u1ecbch v\u1ee5 c\u1ee7a ch\xfang t\xf4i\n\u2022 G\u1eedi th\xf4ng tin khuy\u1ebfn m\xe3i (n\u1ebfu b\u1ea1n \u0111\u1ed3ng \xfd nh\u1eadn)\n\u2022 Tu\xe2n th\u1ee7 c\xe1c y\xeau c\u1ea7u ph\xe1p l\xfd")
B.a5r=new A.dB("5. Giao H\xe0ng","Th\u1eddi gian giao h\xe0ng ph\u1ee5 thu\u1ed9c v\xe0o:\n\n\u2022 \u0110\u1ecba \u0111i\u1ec3m giao h\xe0ng\n\u2022 T\xecnh tr\u1ea1ng kho h\xe0ng\n\u2022 \u0110i\u1ec1u ki\u1ec7n th\u1eddi ti\u1ebft v\xe0 giao th\xf4ng\n\nCh\xfang t\xf4i s\u1ebd c\u1ed1 g\u1eafng giao h\xe0ng \u0111\xfang h\u1eb9n nh\u01b0ng kh\xf4ng ch\u1ecbu tr\xe1ch nhi\u1ec7m cho c\xe1c tr\u01b0\u1eddng h\u1ee3p ch\u1eadm tr\u1ec5 ngo\xe0i t\u1ea7m ki\u1ec3m so\xe1t (thi\xean tai, d\u1ecbch b\u1ec7nh, v.v.).")
B.a5s=new A.dB("4. B\u1ea3o M\u1eadt Th\xf4ng Tin","Ch\xfang t\xf4i \xe1p d\u1ee5ng c\xe1c bi\u1ec7n ph\xe1p b\u1ea3o m\u1eadt k\u1ef9 thu\u1eadt v\xe0 t\u1ed5 ch\u1ee9c ph\xf9 h\u1ee3p \u0111\u1ec3 b\u1ea3o v\u1ec7 th\xf4ng tin c\xe1 nh\xe2n c\u1ee7a b\u1ea1n kh\u1ecfi truy c\u1eadp, s\u1eed d\u1ee5ng, ho\u1eb7c ti\u1ebft l\u1ed9 tr\xe1i ph\xe9p. Tuy nhi\xean, kh\xf4ng c\xf3 ph\u01b0\u01a1ng th\u1ee9c truy\u1ec1n t\u1ea3i qua Internet ho\u1eb7c ph\u01b0\u01a1ng th\u1ee9c l\u01b0u tr\u1eef \u0111i\u1ec7n t\u1eed n\xe0o l\xe0 an to\xe0n tuy\u1ec7t \u0111\u1ed1i.")
B.a5t=new A.dB("5. Chia S\u1ebb Th\xf4ng Tin","Ch\xfang t\xf4i kh\xf4ng b\xe1n ho\u1eb7c cho thu\xea th\xf4ng tin c\xe1 nh\xe2n c\u1ee7a b\u1ea1n cho b\xean th\u1ee9 ba. Th\xf4ng tin c\xf3 th\u1ec3 \u0111\u01b0\u1ee3c chia s\u1ebb v\u1edbi:\n\n\u2022 \u0110\u1ed1i t\xe1c v\u1eadn chuy\u1ec3n \u0111\u1ec3 giao h\xe0ng\n\u2022 Nh\xe0 cung c\u1ea5p d\u1ecbch v\u1ee5 thanh to\xe1n \u0111\u1ec3 x\u1eed l\xfd giao d\u1ecbch\n\u2022 C\u01a1 quan ch\u1ee9c n\u0103ng khi c\xf3 y\xeau c\u1ea7u ph\xe1p l\xfd")
B.a5u=new A.dB("1. Ch\u1ea5p Nh\u1eadn \u0110i\u1ec1u Kho\u1ea3n","B\u1eb1ng vi\u1ec7c truy c\u1eadp v\xe0 s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 c\u1ee7a N\xf4ng S\u1ea3n T\xf9ng B\xe1ch, b\u1ea1n \u0111\u1ed3ng \xfd tu\xe2n theo v\xe0 b\u1ecb r\xe0ng bu\u1ed9c b\u1edfi c\xe1c \u0111i\u1ec1u kho\u1ea3n v\xe0 \u0111i\u1ec1u ki\u1ec7n sau \u0111\xe2y. N\u1ebfu b\u1ea1n kh\xf4ng \u0111\u1ed3ng \xfd v\u1edbi b\u1ea5t k\u1ef3 ph\u1ea7n n\xe0o c\u1ee7a c\xe1c \u0111i\u1ec1u kho\u1ea3n n\xe0y, vui l\xf2ng kh\xf4ng s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 c\u1ee7a ch\xfang t\xf4i.")
B.a5v=new A.dB("3. \u0110\u1eb7t H\xe0ng v\xe0 Thanh To\xe1n","Khi \u0111\u1eb7t h\xe0ng, b\u1ea1n \u0111\u1ed3ng \xfd:\n\n\u2022 Cung c\u1ea5p th\xf4ng tin ch\xednh x\xe1c v\xe0 \u0111\u1ea7y \u0111\u1ee7\n\u2022 Thanh to\xe1n \u0111\u1ea7y \u0111\u1ee7 theo ph\u01b0\u01a1ng th\u1ee9c \u0111\xe3 th\u1ecfa thu\u1eadn\n\u2022 Nh\u1eadn h\xe0ng \u0111\xfang th\u1eddi gian \u0111\xe3 h\u1eb9n\n\u2022 Ki\u1ec3m tra h\xe0ng h\xf3a khi nh\u1eadn v\xe0 b\xe1o ngay n\u1ebfu c\xf3 v\u1ea5n \u0111\u1ec1\n\nCh\xfang t\xf4i c\xf3 quy\u1ec1n t\u1eeb ch\u1ed1i ho\u1eb7c h\u1ee7y \u0111\u01a1n h\xe0ng n\u1ebfu ph\xe1t hi\u1ec7n th\xf4ng tin kh\xf4ng ch\xednh x\xe1c ho\u1eb7c gian l\u1eadn.")
B.a5w=new A.dB("1. Gi\u1edbi Thi\u1ec7u","N\xf4ng S\u1ea3n T\xf9ng B\xe1ch cam k\u1ebft b\u1ea3o v\u1ec7 quy\u1ec1n ri\xeang t\u01b0 c\u1ee7a kh\xe1ch h\xe0ng. Ch\xednh s\xe1ch b\u1ea3o m\u1eadt n\xe0y gi\u1ea3i th\xedch c\xe1ch ch\xfang t\xf4i thu th\u1eadp, s\u1eed d\u1ee5ng, v\xe0 b\u1ea3o v\u1ec7 th\xf4ng tin c\xe1 nh\xe2n c\u1ee7a b\u1ea1n khi b\u1ea1n s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 c\u1ee7a ch\xfang t\xf4i.")
B.a5x=new A.dB("9. Gi\u1edbi H\u1ea1n Tr\xe1ch Nhi\u1ec7m","N\xf4ng S\u1ea3n T\xf9ng B\xe1ch kh\xf4ng ch\u1ecbu tr\xe1ch nhi\u1ec7m cho:\n\n\u2022 Thi\u1ec7t h\u1ea1i gi\xe1n ti\u1ebfp, ng\u1eabu nhi\xean, ho\u1eb7c h\u1eadu qu\u1ea3\n\u2022 M\u1ea5t m\xe1t d\u1eef li\u1ec7u ho\u1eb7c th\xf4ng tin\n\u2022 Gi\xe1n \u0111o\u1ea1n d\u1ecbch v\u1ee5 do s\u1ef1 c\u1ed1 k\u1ef9 thu\u1eadt\n\u2022 H\xe0nh \u0111\u1ed9ng c\u1ee7a b\xean th\u1ee9 ba (v\u1eadn chuy\u1ec3n, thanh to\xe1n)\n\nTr\xe1ch nhi\u1ec7m t\u1ed1i \u0111a c\u1ee7a ch\xfang t\xf4i gi\u1edbi h\u1ea1n \u1edf gi\xe1 tr\u1ecb \u0111\u01a1n h\xe0ng.")
B.a5y=new A.dB("2. Th\xf4ng Tin Ch\xfang T\xf4i Thu Th\u1eadp","Ch\xfang t\xf4i c\xf3 th\u1ec3 thu th\u1eadp c\xe1c th\xf4ng tin sau:\n\n\u2022 Th\xf4ng tin c\xe1 nh\xe2n: T\xean, \u0111\u1ecba ch\u1ec9, s\u1ed1 \u0111i\u1ec7n tho\u1ea1i, \u0111\u1ecba ch\u1ec9 email\n\u2022 Th\xf4ng tin giao d\u1ecbch: L\u1ecbch s\u1eed mua h\xe0ng, \u0111\u01a1n \u0111\u1eb7t h\xe0ng\n\u2022 Th\xf4ng tin k\u1ef9 thu\u1eadt: \u0110\u1ecba ch\u1ec9 IP, lo\u1ea1i tr\xecnh duy\u1ec7t, thi\u1ebft b\u1ecb truy c\u1eadp\n\u2022 Th\xf4ng tin s\u1eed d\u1ee5ng: C\xe1ch b\u1ea1n t\u01b0\u01a1ng t\xe1c v\u1edbi website v\xe0 d\u1ecbch v\u1ee5 c\u1ee7a ch\xfang t\xf4i")
B.a5z=new A.dB("8. Tr\xe1ch Nhi\u1ec7m Ng\u01b0\u1eddi D\xf9ng","Khi s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5, b\u1ea1n \u0111\u1ed3ng \xfd:\n\n\u2022 Kh\xf4ng s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 cho m\u1ee5c \u0111\xedch b\u1ea5t h\u1ee3p ph\xe1p\n\u2022 Kh\xf4ng cung c\u1ea5p th\xf4ng tin sai l\u1ec7ch\n\u2022 Kh\xf4ng l\xe0m \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn ho\u1ea1t \u0111\u1ed9ng c\u1ee7a h\u1ec7 th\u1ed1ng\n\u2022 Tu\xe2n th\u1ee7 m\u1ecdi quy \u0111\u1ecbnh ph\xe1p lu\u1eadt hi\u1ec7n h\xe0nh\n\u2022 T\xf4n tr\u1ecdng quy\u1ec1n s\u1edf h\u1eefu tr\xed tu\u1ec7 c\u1ee7a ch\xfang t\xf4i")
B.a5A=new A.dB("10. Quy\u1ec1n S\u1edf H\u1eefu Tr\xed Tu\u1ec7","T\u1ea5t c\u1ea3 n\u1ed9i dung tr\xean website bao g\u1ed3m v\u0103n b\u1ea3n, h\xecnh \u1ea3nh, logo, thi\u1ebft k\u1ebf l\xe0 t\xe0i s\u1ea3n c\u1ee7a N\xf4ng S\u1ea3n T\xf9ng B\xe1ch v\xe0 \u0111\u01b0\u1ee3c b\u1ea3o v\u1ec7 b\u1edfi lu\u1eadt s\u1edf h\u1eefu tr\xed tu\u1ec7. Nghi\xeam c\u1ea5m sao ch\xe9p, ph\xe2n ph\u1ed1i, ho\u1eb7c s\u1eed d\u1ee5ng m\xe0 kh\xf4ng c\xf3 s\u1ef1 cho ph\xe9p b\u1eb1ng v\u0103n b\u1ea3n.")
B.a5B=new A.dB("7. B\u1ea3o H\xe0nh v\xe0 Cam K\u1ebft Ch\u1ea5t L\u01b0\u1ee3ng","Ch\xfang t\xf4i cam k\u1ebft:\n\n\u2022 S\u1ea3n ph\u1ea9m ch\xednh h\xe3ng, ngu\u1ed3n g\u1ed1c r\xf5 r\xe0ng\n\u2022 Ch\u1ea5t l\u01b0\u1ee3ng \u0111\xfang nh\u01b0 m\xf4 t\u1ea3\n\u2022 H\u1ed7 tr\u1ee3 k\u1ef9 thu\u1eadt sau b\xe1n h\xe0ng\n\nTuy nhi\xean, ch\xfang t\xf4i kh\xf4ng ch\u1ecbu tr\xe1ch nhi\u1ec7m cho:\n\n\u2022 Thi\u1ec7t h\u1ea1i do s\u1eed d\u1ee5ng sai h\u01b0\u1edbng d\u1eabn\n\u2022 K\u1ebft qu\u1ea3 canh t\xe1c ph\u1ee5 thu\u1ed9c v\xe0o nhi\u1ec1u y\u1ebfu t\u1ed1 kh\xe1ch quan\n\u2022 S\u1ea3n ph\u1ea9m \u0111\xe3 qu\xe1 h\u1ea1n s\u1eed d\u1ee5ng")
B.a5C=new A.dB("11. Thay \u0110\u1ed5i \u0110i\u1ec1u Kho\u1ea3n","Ch\xfang t\xf4i c\xf3 quy\u1ec1n c\u1eadp nh\u1eadt v\xe0 thay \u0111\u1ed5i \u0111i\u1ec1u kho\u1ea3n s\u1eed d\u1ee5ng n\xe0y b\u1ea5t c\u1ee9 l\xfac n\xe0o. C\xe1c thay \u0111\u1ed5i c\xf3 hi\u1ec7u l\u1ef1c ngay sau khi \u0111\u0103ng t\u1ea3i tr\xean website. Vi\u1ec7c b\u1ea1n ti\u1ebfp t\u1ee5c s\u1eed d\u1ee5ng d\u1ecbch v\u1ee5 sau khi c\xf3 thay \u0111\u1ed5i \u0111\u1ed3ng ngh\u0129a v\u1edbi vi\u1ec7c b\u1ea1n ch\u1ea5p nh\u1eadn c\xe1c \u0111i\u1ec1u kho\u1ea3n m\u1edbi.")
B.a5D=new A.dB("8. Thay \u0110\u1ed5i Ch\xednh S\xe1ch","Ch\xfang t\xf4i c\xf3 th\u1ec3 c\u1eadp nh\u1eadt ch\xednh s\xe1ch b\u1ea3o m\u1eadt n\xe0y theo th\u1eddi gian. M\u1ecdi thay \u0111\u1ed5i s\u1ebd \u0111\u01b0\u1ee3c \u0111\u0103ng t\u1ea3i tr\xean trang n\xe0y v\u1edbi ng\xe0y c\u1eadp nh\u1eadt m\u1edbi. Ch\xfang t\xf4i khuy\u1ebfn kh\xedch b\u1ea1n xem l\u1ea1i ch\xednh s\xe1ch n\xe0y \u0111\u1ecbnh k\u1ef3.")
B.a5E=new A.dB("6. Quy\u1ec1n C\u1ee7a B\u1ea1n","B\u1ea1n c\xf3 quy\u1ec1n:\n\n\u2022 Truy c\u1eadp v\xe0 xem th\xf4ng tin c\xe1 nh\xe2n c\u1ee7a m\xecnh\n\u2022 Y\xeau c\u1ea7u ch\u1ec9nh s\u1eeda ho\u1eb7c c\u1eadp nh\u1eadt th\xf4ng tin\n\u2022 Y\xeau c\u1ea7u x\xf3a th\xf4ng tin c\xe1 nh\xe2n (trong m\u1ed9t s\u1ed1 tr\u01b0\u1eddng h\u1ee3p)\n\u2022 T\u1eeb ch\u1ed1i nh\u1eadn th\xf4ng tin ti\u1ebfp th\u1ecb\n\u2022 Khi\u1ebfu n\u1ea1i v\u1ec1 c\xe1ch ch\xfang t\xf4i x\u1eed l\xfd th\xf4ng tin c\u1ee7a b\u1ea1n")
B.a5F=new A.dB("4. Gi\xe1 C\u1ea3 v\xe0 Khuy\u1ebfn M\xe3i","Gi\xe1 c\u1ea3 s\u1ea3n ph\u1ea9m c\xf3 th\u1ec3 thay \u0111\u1ed5i theo th\u1eddi gian v\xe0 th\u1ecb tr\u01b0\u1eddng. Gi\xe1 \xe1p d\u1ee5ng l\xe0 gi\xe1 t\u1ea1i th\u1eddi \u0111i\u1ec3m x\xe1c nh\u1eadn \u0111\u01a1n h\xe0ng.\n\nC\xe1c ch\u01b0\u01a1ng tr\xecnh khuy\u1ebfn m\xe3i c\xf3 th\u1eddi h\u1ea1n gi\u1edbi h\u1ea1n v\xe0 \u0111i\u1ec1u ki\u1ec7n \xe1p d\u1ee5ng c\u1ee5 th\u1ec3. Ch\xfang t\xf4i c\xf3 quy\u1ec1n thay \u0111\u1ed5i ho\u1eb7c k\u1ebft th\xfac ch\u01b0\u01a1ng tr\xecnh khuy\u1ebfn m\xe3i b\u1ea5t c\u1ee9 l\xfac n\xe0o.")
B.a5G=new A.dB("7. Cookies","Website c\u1ee7a ch\xfang t\xf4i s\u1eed d\u1ee5ng cookies \u0111\u1ec3 c\u1ea3i thi\u1ec7n tr\u1ea3i nghi\u1ec7m ng\u01b0\u1eddi d\xf9ng. Cookies l\xe0 c\xe1c t\u1ec7p v\u0103n b\u1ea3n nh\u1ecf \u0111\u01b0\u1ee3c l\u01b0u tr\u1eef tr\xean thi\u1ebft b\u1ecb c\u1ee7a b\u1ea1n. B\u1ea1n c\xf3 th\u1ec3 t\u1eaft cookies trong c\xe0i \u0111\u1eb7t tr\xecnh duy\u1ec7t, nh\u01b0ng \u0111i\u1ec1u n\xe0y c\xf3 th\u1ec3 \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn ch\u1ee9c n\u0103ng c\u1ee7a website.")
B.a5H=new A.dB("6. \u0110\u1ed5i Tr\u1ea3 v\xe0 Ho\xe0n Ti\u1ec1n","Ch\xednh s\xe1ch \u0111\u1ed5i tr\u1ea3:\n\n\u2022 S\u1ea3n ph\u1ea9m l\u1ed7i ho\u1eb7c kh\xf4ng \u0111\xfang m\xf4 t\u1ea3: \u0110\u1ed5i tr\u1ea3 trong v\xf2ng 7 ng\xe0y\n\u2022 S\u1ea3n ph\u1ea9m c\xf2n nguy\xean tem, m\xe1c, bao b\xec\n\u2022 C\xf3 h\xf3a \u0111\u01a1n mua h\xe0ng h\u1ee3p l\u1ec7\n\u2022 Ph\xe2n b\xf3n v\xe0 c\xe1m \u0111\xe3 m\u1edf kh\xf4ng \u0111\u01b0\u1ee3c \u0111\u1ed5i tr\u1ea3 (tr\u1eeb l\u1ed7i s\u1ea3n xu\u1ea5t)\n\nTh\u1eddi gian ho\xe0n ti\u1ec1n: 7-14 ng\xe0y l\xe0m vi\u1ec7c sau khi x\xe1c nh\u1eadn \u0111\u1ed5i tr\u1ea3.")
B.a5I=new A.dB("12. Lu\u1eadt \xc1p D\u1ee5ng","C\xe1c \u0111i\u1ec1u kho\u1ea3n n\xe0y \u0111\u01b0\u1ee3c \u0111i\u1ec1u ch\u1ec9nh b\u1edfi lu\u1eadt ph\xe1p Vi\u1ec7t Nam. M\u1ecdi tranh ch\u1ea5p ph\xe1t sinh s\u1ebd \u0111\u01b0\u1ee3c gi\u1ea3i quy\u1ebft th\xf4ng qua th\u01b0\u01a1ng l\u01b0\u1ee3ng, h\xf2a gi\u1ea3i, ho\u1eb7c t\u1ea1i T\xf2a \xe1n c\xf3 th\u1ea9m quy\u1ec1n t\u1ea1i Vi\u1ec7t Nam.")
B.a5J=new A.dB("13. Li\xean H\u1ec7","N\u1ebfu b\u1ea1n c\xf3 c\xe2u h\u1ecfi v\u1ec1 \u0111i\u1ec1u kho\u1ea3n s\u1eed d\u1ee5ng n\xe0y, vui l\xf2ng li\xean h\u1ec7 v\u1edbi ch\xfang t\xf4i \u0111\u1ec3 \u0111\u01b0\u1ee3c h\u1ed7 tr\u1ee3.")
B.a5K=new A.dB("2. D\u1ecbch V\u1ee5","N\xf4ng S\u1ea3n T\xf9ng B\xe1ch cung c\u1ea5p c\xe1c d\u1ecbch v\u1ee5 sau:\n\n\u2022 Ph\xe2n ph\u1ed1i ph\xe2n b\xf3n v\xe0 c\xe1m ch\u1ea5t l\u01b0\u1ee3ng cao\n\u2022 Thu mua n\xf4ng s\u1ea3n t\u1eeb ng\u01b0\u1eddi n\xf4ng d\xe2n\n\u2022 T\u01b0 v\u1ea5n k\u1ef9 thu\u1eadt v\u1ec1 canh t\xe1c v\xe0 ch\u0103n nu\xf4i\n\u2022 Cung c\u1ea5p th\xf4ng tin v\xe0 h\u1ed7 tr\u1ee3 kh\xe1ch h\xe0ng\n\nCh\xfang t\xf4i c\xf3 quy\u1ec1n thay \u0111\u1ed5i, t\u1ea1m ng\u01b0ng, ho\u1eb7c ch\u1ea5m d\u1ee9t b\u1ea5t k\u1ef3 d\u1ecbch v\u1ee5 n\xe0o m\xe0 kh\xf4ng c\u1ea7n th\xf4ng b\xe1o tr\u01b0\u1edbc.")
